{
  "mode": "method",
  "tests": [
    {
      "name": "valid_country_lookup",
      "input": {
        "countryCode": "US"
      },
      "output": {
        "fromDB": true,
        "result": {
          "name": "United States",
          "code": "US"
        }
      },
      "notes": "Valid lookup for a country should return the expected format."
    },
    {
      "name": "valid_device_lookup",
      "input": {
        "deviceId": "12345"
      },
      "output": {
        "fromDB": true,
        "result": {
          "name": "Device A",
          "id": "12345"
        }
      },
      "notes": "Valid lookup for a device should return the expected format."
    },
    {
      "name": "country_lookup_with_unnecessary_fields",
      "input": {
        "countryCode": "US"
      },
      "output": {
        "fromDB": true,
        "result": {
          "name": "United States",
          "code": "US"
        }
      },
      "notes": "Ensure unnecessary fields like createdAt, updatedAt are not included."
    },
    {
      "name": "invalid_country_lookup",
      "input": {
        "countryCode": "INVALID"
      },
      "output": {
        "fromDB": true,
        "result": null
      },
      "notes": "Invalid country code should return null in the result."
    },
    {
      "name": "swagger_security_mapping",
      "input": {
        "endpoint": "/v6/lookups/countries"
      },
      "output": {
        "secured": false
      },
      "notes": "Ensure the Swagger documentation correctly reflects security requirements."
    },
    {
      "name": "base_path_check",
      "input": {
        "endpoint": "/lookups/countries"
      },
      "output": {
        "error": "Not Found"
      },
      "notes": "Check that the API returns a 404 for incorrect base path."
    },
    {
      "name": "error_handling_format",
      "input": {
        "countryCode": "ERROR"
      },
      "output": {
        "fromDB": true,
        "result": {
          "error": "Invalid request"
        }
      },
      "notes": "Ensure error responses maintain the specified format."
    },
    {
      "name": "remove_unnecessary_fields_check",
      "input": {
        "deviceId": "12345"
      },
      "output": {
        "fromDB": true,
        "result": {
          "name": "Device A",
          "id": "12345"
        }
      },
      "notes": "Verify that unnecessary fields are not returned in the response."
    }
  ],
  "assumptions": "All endpoints are expected to follow the new response format and security configurations.",
  "notes": "Tests should cover both valid and invalid scenarios to ensure robustness."
}
